(function(w){"use strict";const ID="dday";function parse(v){const [y,m,d]=String(v).split("-").map(Number);const dt=new Date(y,m-1,d);return dt&&dt.getFullYear()===y&&dt.getMonth()===m-1&&dt.getDate()===d?dt:null}function compute(x){const today=parse(x.today),target=parse(x.target);if(!today||!target)return{error:"기준일과 목표일을 올바르게 선택해 주세요."};const days=Math.round((Date.UTC(target.getFullYear(),target.getMonth(),target.getDate())-Date.UTC(today.getFullYear(),today.getMonth(),today.getDate()))/86400000);return{days,label:days===0?"D-DAY":days>0?`D-${days}`:`D+${Math.abs(days)}`}}function render(root,api){root.innerHTML=`<div class="hm-calc-panel"><div class="hm-calc-form"><div class="hm-calc-grid-2"><div class="hm-calc-field"><label>기준일</label><input type="date" class="hm-calc-input"></div><div class="hm-calc-field"><label>목표일</label><input type="date" class="hm-calc-input"></div></div><div class="hm-calc-actions"><button type="button" class="hm-calc-btn">D-day 계산하기</button></div><p class="hm-calc-message" hidden></p></div><div class="hm-calc-result" hidden></div></div>`;const [today,target]=root.querySelectorAll("input"),go=root.querySelector("button"),msg=root.querySelector(".hm-calc-message"),res=root.querySelector(".hm-calc-result");today.value=api.localDateString();go.addEventListener("click",()=>{const r=compute({today:today.value,target:target.value});if(r.error){api.setMessage(msg,r.error);api.clearResult(res);return}api.setMessage(msg,"");api.setResult(res,api.resultCard("D-day",r.label,`기준일과 목표일의 차이는 ${api.formatNumber(Math.abs(r.days),0)}일입니다.`));});}w.HM_CALC.register(ID,{compute,render});})(window);
